#include <print>
#include <cmath>

consteval double compile_time_sqrt(double x) {
    // Newton's method — evaluated only at compile time
    double r = x;
    for (int i = 0; i < 10; ++i) r = (r + x/r) / 2;
    return r;
}

constexpr double my_sqrt(double x) {
    if consteval {
        return compile_time_sqrt(x); // safe: we are in a compile-time context
    } else {
        return std::sqrt(x); // runtime: use libm
    }
}

int main() {
    constexpr double ct = my_sqrt(2.0); // compile-time path
    double rt = my_sqrt(2.0);           // runtime path
    std::println("compile-time: {:.6f}", ct);
    std::println("runtime:      {:.6f}", rt);
}

#include <print>
#include <string>

// abbreviated function template — instantiated for each distinct argument type
void describe(const auto& x) {
    std::println("value: {}", x);
}

// overload for string — more specific, wins for string arguments
void describe(const std::string& s) {
    std::println("string of length {}: {}", s.size(), s);
}

// multiple auto params — each is a separate template parameter
auto add(auto a, auto b) {
    return a + b;
}

int main() {
    describe(42);
    describe(3.14);
    describe(std::string{"hello"});

    std::println("add: {}", add(1, 2));
    std::println("add: {}", add(1.5, 2.5));
    std::println("add: {}", add(std::string{"foo"}, std::string{"bar"}));
}

#include <print>
#include <cstddef>

struct Matrix3x3 {
    double data[3][3]{};

    double& operator[](size_t i, size_t j) { return data[i][j]; }
    const double& operator[](size_t i, size_t j) const { return data[i][j]; }
};

int main() {
    Matrix3x3 m;
    m[0, 0] = 1.0;
    m[1, 1] = 2.0;
    m[2, 2] = 3.0;

    for (size_t i = 0; i < 3; ++i) {
        for (size_t j = 0; j < 3; ++j) {
            std::print("{:.0f} ", m[i, j]);
        }
        std::println("");
    }
}

#include <print>
#include <cstddef>

struct Tensor3D {
    double data[2][2][2]{};

    double& operator[](size_t i, size_t j, size_t k) {
        return data[i][j][k];
    }
};

int main() {
    Tensor3D t;
    t[0, 0, 0] = 1.0;
    t[0, 0, 1] = 2.0;
    t[1, 0, 0] = 3.0;
    t[1, 1, 1] = 4.0;

    std::println("t[0,0,0] = {:.0f}", t[0, 0, 0]);
    std::println("t[0,0,1] = {:.0f}", t[0, 0, 1]);
    std::println("t[1,0,0] = {:.0f}", t[1, 0, 0]);
    std::println("t[1,1,1] = {:.0f}", t[1, 1, 1]);
}

#include <print>
#include <vector>
#include <stdexcept>
#include <cstddef>

// Dynamic 2D grid — the same pattern that std::mdspan uses internally:
// a flat storage buffer + flat-index computation inside operator[]
struct Grid {
    size_t rows, cols;
    std::vector<double> data;

    Grid(size_t r, size_t c) : rows(r), cols(c), data(r * c, 0.0) {}

    double& operator[](size_t i, size_t j) {
        if (i >= rows || j >= cols) throw std::out_of_range("Grid: index out of range");
        return data[i * cols + j];
    }

    double operator[](size_t i, size_t j) const {
        if (i >= rows || j >= cols) throw std::out_of_range("Grid: index out of range");
        return data[i * cols + j];
    }
};

int main() {
    Grid g{3, 4};
    g[0, 0] = 1.0;
    g[1, 2] = 5.0;
    g[2, 3] = 9.0;

    std::println("g[0,0] = {:.0f}", g[0, 0]);
    std::println("g[1,2] = {:.0f}", g[1, 2]);
    std::println("g[2,3] = {:.0f}", g[2, 3]);
    std::println("g[0,1] = {:.0f}", g[0, 1]);

    try {
        [[maybe_unused]] double x = g[5, 0]; // out of bounds
    } catch (const std::out_of_range& e) {
        std::println("caught: {}", e.what());
    }
}

#include <print>
#include <string>
#include <vector>

int main() {
    // 1. Basic decay-copy: strip reference and cv-qualifiers
    std::string original = "hello";
    const std::string& ref = original;
    auto copy = auto(ref);  // copy is std::string, not const std::string&
    std::println("copy: {}", copy);

    // 2. In a lambda capture — safe copy of a reference
    std::string msg = "world";
    auto printer = [captured = auto(msg)] {
        std::println("captured: {}", captured);
    };
    msg = "changed";
    printer();  // prints "world", not "changed"

    // 3. auto{x} — equivalent brace form
    int arr[3] = {1, 2, 3};
    auto* ptr = auto(arr);  // array decays to pointer
    std::println("ptr[0]: {}", ptr[0]);
}

#include <print>

int main() {
    int value = 10;

    // C++23: mutable lambda without () — captures by value, modifies the copy
    auto increment = [value] mutable {
        ++value;
        std::println("inside: {}", value);
    };
    increment();  // inside: 11
    increment();  // inside: 12
    std::println("outside: {}", value);  // unchanged: 10

    // C++23: trailing return type without ()
    auto to_long = [] -> long long { return 1'000'000'000LL * 3; };
    std::println("to_long: {}", to_long());

    // C++23: noexcept without ()
    auto safe_neg = [](int n) noexcept { return -n; };
    std::println("safe_neg(7): {}", safe_neg(7));

    // C++23: constexpr without ()
    auto pi_approx = [] constexpr { return 3.14159; };
    std::println("pi: {}", pi_approx());
}
